    def readFile(self):
        file, check = QFileDialog.getOpenFileName(None, "QFileDialog.getOpenFileName()", "", "CSV Files (*.csv)")
        #stationList = []
        if check:
            f = open(file, "r", encoding ='utf-8-sig')
            for train in f:
                stationList = []
                train = train.strip('\n')
                info = train.split(',')
                line = info[0]
                for i in range(1, 21):
                    if len(info[i]) > 0:
                        stationList.append(info[i])
                arrival_time = info[21].replace('"','')
                self.CTC.addTrain2(stationList, arrival_time, line)



