    def stop_time(self):
        self.CTC.time_toggle = 0

    def start_time(self):
        self.CTC.time_toggle = 1

    def updateTrack(self):
        index = int(self.trackSelect.currentText()) -1
        line = self.lineSelect.currentText()
        value = self.radioButton.isChecked()
        if line == "Green":
            l = 2
        elif line == "Red":
            l = 1
        else:
            l = 0

        self.CTC.editTrack(l, index, value)
        #track[int(self.trackSelect.currentText()) -1] = self.radioButton.isChecked()

        self.updateAutoTable()
        self.updateTrackStatus()

    def updateCombo(self):
        for i in range(self.trainSelect.count()-1, len(self.CTC.getTrainList())):
            if self.CTC.getTrainList()[i].location != -1:
                self.trainSelect.addItem(str(i+1))

    def updateTrain(self):
        train = self.trainSelect.currentText()
        line = self.lineSelect1.currentText()
        destination = self.stationSelect.currentText()

        destination = destination.split(" ")[0]
        time = self.timeSelect.time().toString()

        if(train == "New Train"):

            self.CTC.addTrain(int(destination), str(time), str(line))
            #New = Train()
            #New.setTrainID(len(self.officeList)+1)
            #New.setDestination(destination)
            #New.setArrival_time(str(time))
            #self.officeList.append(New)
            self.trainSelect.addItem(str(len(self.CTC.getTrainList())))
            self.updateAutoTable()
        else:
            id = int(self.trainSelect.currentText()) - 1
            self.CTC.editTrain(id, destination, str(time))
            #self.officeList[int(self.trainSelect.currentText())-1].destination = self.stationSelect.currentText()
            #self.officeList[int(self.trainSelect.currentText())-1].arrival_time = str(self.timeSelect.time().toString())
            self.updateManualTable()


    def updateMaintenanceTable(self):
        if self.lineSelect.currentText() == "Green":
            line = 2
        elif self.lineSelect.currentText() == "Red":
            line = 1
        else:
            line = 0

        track = self.CTC.getTrackList(line)
        self.maintenanceTable.setRowCount(1)
        self.maintenanceTable.setItem(0, 0, QtWidgets.QTableWidgetItem(str(self.lineSelect.currentText())))
        self.maintenanceTable.setItem(0, 1, QtWidgets.QTableWidgetItem(str(self.trackSelect.currentIndex()+1)))


        if track[int(self.trackSelect.currentIndex())] != 2:
            self.maintenanceTable.setItem(0, 2, QtWidgets.QTableWidgetItem(str("Open")))
        else:
            self.maintenanceTable.setItem(0, 2, QtWidgets.QTableWidgetItem(str("Closed")))
        if self.radioButton.isChecked():
            self.maintenanceTable.setItem(0, 3, QtWidgets.QTableWidgetItem(str("Open")))
        else:
            self.maintenanceTable.setItem(0, 3, QtWidgets.QTableWidgetItem(str("Closed")))



    def updateAutoTable(self):
        trainList = self.CTC.getTrainList()
        self.autoTable.setRowCount(len(trainList))
        for i, train in enumerate(trainList):
            if train.location != -1:
                self.autoTable.setItem(i, 0, QtWidgets.QTableWidgetItem(str(train.train_id)))
                self.autoTable.setItem(i, 1, QtWidgets.QTableWidgetItem(str(train.destination)))
                self.autoTable.setItem(i, 2, QtWidgets.QTableWidgetItem(train.arrival_time))
                self.autoTable.setItem(i, 3, QtWidgets.QTableWidgetItem(str(train.location)))
                self.autoTable.setItem(i, 4, QtWidgets.QTableWidgetItem(str(train.line)))


        station = self.CTC.getStationList()
        # self.auto2table.setRowCount(len(station))
        # for i in range(len(station)):
        #     self.auto2table.setItem(i, 0, QtWidgets.QTableWidgetItem(str(i+1)))
        #     self.auto2table.setItem(i, 1, QtWidgets.QTableWidgetItem(str(station[i])))


        index = []
        n = int(self.lineSelect.currentIndex())

        if n == 1:
            num = 2
        elif n == 2:
            num = 1
        else:
            num = 0
        track = self.CTC.getTrackList(num)
        count = track.count(2)
        self.auto3table.setRowCount(count)
        for x in range(len(track)):
            if track[x] == 2:
                index.append(x+1)
        for x in range(count):
            self.auto3table.setItem(x, 0, QtWidgets.QTableWidgetItem(str(index[x])))
            self.auto3table.setItem(x, 1, QtWidgets.QTableWidgetItem("Closed"))

        station = self.CTC.getStationList()
        # self.stationBCount.display(str(station[0]))
        # self.stationCCount.display(str(station[1]))


    def updateManualTable(self):
        trainList = self.CTC.getTrainList()
        self.manualTable.setRowCount(1)
        self.manualTable.setItem(0, 0, QtWidgets.QTableWidgetItem(self.trainSelect.currentText()))
        if(self.trainSelect.currentText() != "New Train"):
            self.manualTable.setItem(0, 1, QtWidgets.QTableWidgetItem(trainList[int(self.trainSelect.currentText())-1].destination))
        else:
            self.manualTable.setItem(0, 1, QtWidgets.QTableWidgetItem("NA"))
        self.manualTable.setItem(0, 2, QtWidgets.QTableWidgetItem(self.stationSelect.currentText()))
        self.manualTable.setItem(0, 3, QtWidgets.QTableWidgetItem(self.timeSelect.time().toString()))

        self.autoTable.setRowCount(len(trainList))
        for i in range(len(trainList)):
            if trainList[i].completed != 1:
                self.autoTable.setItem(i, 0, QtWidgets.QTableWidgetItem(str(trainList[i].train_id)))
                self.autoTable.setItem(i, 1, QtWidgets.QTableWidgetItem(trainList[i].destination))
                self.autoTable.setItem(i, 2, QtWidgets.QTableWidgetItem(trainList[i].arrival_time))

    def updateSwitch(self):
        switchnum = self.setSwitch.currentText()
        position = self.setPosition.currentText()
        line = self.lineSelect.currentText()
        self.CTC.setSwitch(position, int(switchnum), line)
